505→  const traceRecord = new RecordId("trace", `trace-${intentId}`);
506→
507→  await surreal.query(`CREATE $trace CONTENT $traceContent;`, {
508→    trace: traceRecord,
509→    traceContent: { type: "intent_submission", actor: identityRecord, workspace: workspaceRecord, created_at: new Date() },
510→  });
511→
512→  await surreal.query(`CREATE $intent CONTENT $content;`, {
513→    intent: intentRecord,
514→    content: {
515→      goal: "Broad test access",
516→      reasoning: "Pre-authorized for acceptance testing",
517→      status: "authorized",
518→      priority: 50,
519→      authorization_details: broadActions,
520→      dpop_jwk_thumbprint: keyPair.thumbprint,
521→      action_spec: { provider: "test", action: "broad_access", params: {} },
522→      trace_id: traceRecord,
523→      requester: identityRecord,
524→      workspace: workspaceRecord,
525→      evaluation: {
526→        decision: "APPROVE",
527→        risk_score: 0,
528→        reason: "Pre-authorized for testing",
529→        evaluated_at: new Date(),
530→        policy_only: true,
531→      },
532→      created_at: new Date(),
533→    },
534→  });
535→
536→  // Request DPoP-bound access token from Custom AS
537→  const tokenUri = `${baseUrl}/api/auth/token`;
538→  const dpopProof = await createDPoPProof(keyPair, "POST", tokenUri);
539→
540→  const tokenRes = await fetch(tokenUri, {
541→    method: "POST",
542→    headers: {
543→      "Content-Type": "application/json",
544→      DPoP: dpopProof,
545→    },
546→    body: JSON.stringify({
547→      grant_type: "urn:brain:intent-authorization",
548→      intent_id: intentId,
549→      authorization_details: broadActions,
550→    }),
551→  });
552→
553→  if (!tokenRes.ok) {
554→    const body = await tokenRes.text();
555→    throw new Error(`DPoP token acquisition failed (${tokenRes.status}): ${body}`);
556→  }
557→
558→  const { access_token } = (await tokenRes.json()) as { access_token: string };
559→
560→  const mcpFetch = async (path: string, options?: { method?: string; body?: unknown }): Promise<Response> => {
561→    const method = options?.method ?? "POST";
562→    const requestUri = `${baseUrl}${path}`;
563→    const proof = await createDPoPProof(keyPair, method, requestUri);
564→
565→    return fetch(requestUri, {
566→      method,
567→      headers: {
568→        "Content-Type": "application/json",
569→        Authorization: `DPoP ${access_token}`,
570→        DPoP: proof,
571→      },
572→      body: options?.body !== undefined ? JSON.stringify(options.body) : JSON.stringify({}),
573→    });
574→  };
575→
576→  return {
577→    ...user,
578→    mcpHeaders: { Authorization: `DPoP ${access_token}` },
579→    mcpFetch,
580→    accessToken: access_token,
581→    keyPair,
582→    workspaceId,
583→    identityId,
584→  };
585→}
586→
587→// ---------------------------------------------------------------------------
588→// DPoP Helpers
589→// ---------------------------------------------------------------------------
590→
591→async function generateDPoPKeyPair(): Promise<DPoPKeyPair> {
592→  const { publicKey, privateKey } = await crypto.subtle.generateKey(
593→    { name: "ECDSA", namedCurve: "P-256" },
594→    true,
595→    ["sign", "verify"],
596→  );
597→
598→  const publicJwk = await crypto.subtle.exportKey("jwk", publicKey);
599→  const thumbprint = await computeDPoPThumbprint(publicJwk);
600→
601→  return { privateKey, publicKey, publicJwk, thumbprint };
602→}
603→
604→async function computeDPoPThumbprint(publicJwk: JsonWebKey): Promise<string> {
605→  const thumbprintInput = JSON.stringify({
606→    crv: publicJwk.crv,
607→    kty: publicJwk.kty,
608→    x: publicJwk.x,
609→    y: publicJwk.y,
610→  });
611→
612→  const hashBuffer = await crypto.subtle.digest(
613→    "SHA-256",
614→    new TextEncoder().encode(thumbprintInput),
615→  );
616→
617→  return base64urlBytes(new Uint8Array(hashBuffer));
618→}
619→
620→async function createDPoPProof(
621→  keyPair: DPoPKeyPair,
622→  method: string,
623→  targetUri: string,
624→): Promise<string> {
625→  const header = {
626→    typ: "dpop+jwt" as const,
627→    alg: "ES256" as const,
628→    jwk: {
629→      kty: keyPair.publicJwk.kty,
630→      crv: keyPair.publicJwk.crv,
631→      x: keyPair.publicJwk.x,
632→      y: keyPair.publicJwk.y,
633→    },
634→  };
635→
636→  const payload = {
637→    jti: crypto.randomUUID(),
638→    htm: method,
639→    htu: targetUri,
640→    iat: Math.floor(Date.now() / 1000),
641→  };
642→
643→  const importedKey = await jose.importJWK(
644→    await crypto.subtle.exportKey("jwk", keyPair.privateKey),
645→    "ES256",
646→  );
647→
648→  return await new jose.SignJWT(payload)
649→    .setProtectedHeader(header)
650→    .sign(importedKey);
651→}
652→
653→function base64urlBytes(bytes: Uint8Array): string {
654→  const binary = String.fromCharCode(...bytes);
655→  return btoa(binary).replace(/\+/g, "-").replace(/\//g, "_").replace(/=/g, "");
656→}
