670→async function withTimeout<T>(callback: () => Promise<T>, timeoutMs: number, label: string): Promise<T> {
671→  return await Promise.race([
672→    callback(),
673→    new Promise<T>((_, reject) => {
674→      setTimeout(() => reject(new Error(`Timed out: ${label}`)), timeoutMs);
675→    }),
676→  ]);
677→}
