323→/**
324→ * Polls until an intent reaches the target status or times out.
325→ * Used to wait for async evaluation pipeline (SurrealQL EVENT -> evaluate -> status update).
326→ */
327→export async function waitForIntentStatus(
328→  surreal: Surreal,
329→  intentId: string,
330→  targetStatus: IntentStatus | IntentStatus[],
331→  timeoutMs = 30_000,
332→): Promise<IntentStatus> {
333→  const targets = Array.isArray(targetStatus) ? targetStatus : [targetStatus];
334→  const start = Date.now();
335→
336→  while (Date.now() - start < timeoutMs) {
337→    const current = await getIntentStatus(surreal, intentId);
338→    if (targets.includes(current)) {
339→      return current;
340→    }
341→    await Bun.sleep(250);
342→  }
343→
344→  const finalStatus = await getIntentStatus(surreal, intentId);
345→  throw new Error(
346→    `Intent ${intentId} did not reach ${targets.join("|")} within ${timeoutMs}ms. ` +
347→    `Current status: ${finalStatus}`,
348→  );
349→}
