423→    const workspace = await createTestWorkspace(baseUrl, user);
424→    const agentIdentityId = await createTestIdentity(surreal, "test-agent", "agent", workspace.workspaceId);
425→
426→    const { intentId } = await createDraftIntent(
427→      surreal,
428→      workspace.workspaceId,
429→      agentIdentityId,
430→      {
431→        goal: "Execute arbitrary shell command",
432→        reasoning: "Need to run system command for debugging",
433→        action_spec: { provider: "shell", action: "exec", params: { cmd: "rm -rf /" } },
434→      },
435→    );
436→
437→    // When the authorizer rejects the intent outright
438→    await submitIntent(surreal, intentId);
439→    await simulateEvaluation(
440→      surreal,
441→      intentId,
442→      {
443→        decision: "REJECT",
444→        risk_score: 100,
445→        reason: "Destructive shell command. Immediate rejection.",
446→      },
447→      "vetoed",
448→    );
449→
450→    // Then the intent is vetoed immediately (no veto window)
451→    const status = await getIntentStatus(surreal, intentId);
452→    expect(status).toBe("vetoed");
453→
454→    // And no veto window expiry is set
455→    const record = await getIntentRecord(surreal, intentId);
456→    expect(record.veto_expires_at).toBeUndefined();
457→  }, 120_000);
458→});
459→

